1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = {
13	  type: string;
14	  material?: string;
15	  enchantment?: number;
16	  cursed?: boolean;
17	};
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type Damage = { itemType: string; amount: number };
20	type ClaimStep = {
21	  op: "claim";
22	  policy: number;
23	  incident: { cause: string; damages: Damage[] };
24	};
25	type Step = QuoteStep | ClaimStep;
26	type Customer = { yearsWithMHPCO: number };
27	type Scenario = { customer: Customer; steps: Step[] };
28	
29	const BLOCK_SIZE = 3;
30	const BLOCK_PREMIUM = 60;
31	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
32	
33	const CURSED_RATE = 0.5;
34	const HIGH_ENCHANTMENT_THRESHOLD = 5;
35	const HIGH_ENCHANTMENT_RATE = 0.3;
36	
37	type Rule<T> = { applies: (subject: T) => boolean; rate: number };
38	
39	const sumApplicableRates = <T>(rules: Rule<T>[], subject: T): number =>
40	  rules
41	    .filter((rule) => rule.applies(subject))
42	    .reduce((sum, rule) => sum + rule.rate, 0);
43	
44	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
45	
46	const isCursed = (item: Item): boolean => item.cursed === true;
47	const isHighlyEnchanted = (item: Item): boolean =>
48	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
49	
50	const SURCHARGE_RULES: Rule<Item>[] = [
51	  { applies: isCursed, rate: CURSED_RATE },
52	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
53	];
54	
55	const countByType = (items: Item[]): Map<string, number> => {
56	  const counts = new Map<string, number>();
57	  for (const item of items) {
58	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
59	  }
60	  return counts;
61	};
62	
63	const basePremiumFor = (type: string) => {
64	  const base = BASE_PREMIUM[type];
65	  if (base === undefined) throw new Error(`Unknown item type: ${type}`);
66	  return base;
67	};
68	
69	const premiumForType = (type: string, count: number) => {
70	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
71	    return BLOCK_PREMIUM;
72	  }
73	  return count * basePremiumFor(type);
74	};
75	
76	const surchargeForItem = (item: Item) =>
77	  basePremiumFor(item.type) * sumApplicableRates(SURCHARGE_RULES, item);
78	
79	const policyBasePremium = (items: Item[]) =>
80	  [...countByType(items)].reduce(
81	    (total, [type, count]) => total + premiumForType(type, count),
82	    0,
83	  );
84	
85	const totalItemSurcharges = (items: Item[]) =>
86	  items.reduce((sum, item) => sum + surchargeForItem(item), 0);
87	
88	const FIRST_INSURANCE_RATE = 0.1;
89	const LOYALTY_THRESHOLD_YEARS = 2;
90	const LOYALTY_RATE = 0.2;
91	const FOLLOWUP_RATE = 0.15;
92	
93	type QuoteContext = { customer: Customer; stepIndex: number };
94	
95	const POLICY_ADJUSTMENTS: Rule<QuoteContext>[] = [
96	  { applies: () => true, rate: FIRST_INSURANCE_RATE },
97	  {
98	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
99	    rate: -LOYALTY_RATE,
100	  },
101	  { applies: ({ stepIndex }) => stepIndex > 0, rate: -FOLLOWUP_RATE },
102	];
103	
104	const policyAdjustment = (ctx: QuoteContext, policyBase: number) =>
105	  policyBase * sumApplicableRates(POLICY_ADJUSTMENTS, ctx);
106	
107	const quote = (step: QuoteStep, customer: Customer, stepIndex: number) => {
108	  const { items } = step;
109	  const policyBase = policyBasePremium(items);
110	  const premium =
111	    policyBase +
112	    policyAdjustment({ customer, stepIndex }, policyBase) +
113	    totalItemSurcharges(items);
114	  return { premium: Math.ceil(premium) + PROCESSING_FEE };
115	};
116	
117	const INSURANCE_VALUE_MULTIPLIER = 10;
118	const DEDUCTIBLE = 100;
119	const CAP_MULTIPLIER = 2;
120	
121	const insuranceValueFor = (type: string) =>
122	  basePremiumFor(type) * INSURANCE_VALUE_MULTIPLIER;
123	
124	const insuranceSum = (items: Item[]) =>
125	  items.reduce((sum, item) => sum + insuranceValueFor(item.type), 0);
126	
127	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
128	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
129	
130	const reimbursableDamage = (item: Item, damage: Damage) =>
131	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
132	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
133	    : damage.amount;
134	
135	const payoutForDamage = (item: Item, damage: Damage) =>
136	  Math.max(0, reimbursableDamage(item, damage) - DEDUCTIBLE);
137	
138	type PolicyState = { items: Item[]; remainingCap: number };
139	
140	const itemForDamage = (items: Item[], damage: Damage): Item => {
141	  const item = items.find((i) => i.type === damage.itemType);
142	  if (!item) throw new Error(`No insured ${damage.itemType} in policy`);
143	  return item;
144	};
145	
146	const totalPayout = (items: Item[], damages: Damage[]) =>
147	  damages.reduce(
148	    (sum, d) => sum + payoutForDamage(itemForDamage(items, d), d),
149	    0,
150	  );
151	
152	const newPolicy = (items: Item[]): PolicyState => ({
153	  items,
154	  remainingCap: insuranceSum(items) * CAP_MULTIPLIER,
155	});
156	
157	const claim = (step: ClaimStep, policies: PolicyState[]) => {
158	  const policy = policies[step.policy];
159	  const payout = totalPayout(policy.items, step.incident.damages);
160	  policy.remainingCap -= payout;
161	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
162	};
163	
164	export const run = (input: Scenario): unknown => {
165	  const policies: PolicyState[] = [];
166	  const results = input.steps.map((step, i) => {
167	    if (step.op === "quote") {
168	      policies[i] = newPolicy(step.items);
169	      return quote(step, input.customer, i);
170	    }
171	    return claim(step, policies);
172	  });
173	  return { results };
174	};
